<?php
// Start output buffering to prevent header HTML from breaking AJAX
ob_start(); 
include('header.php');

// --- AJAX HANDLER FOR STARLINE TIMINGS STATUS TOGGLE ---
if (isset($_POST['action']) && $_POST['action'] == 'toggle_status') {
    // Clear any HTML generated by header.php so we send ONLY the result
    ob_clean(); 
    
    $sn = mysqli_real_escape_string($con, $_POST['sn']);
    $current_status = (int)$_POST['status'];
    
    // Toggle logic: If 1, make 0. If 0, make 1.
    $new_status = ($current_status == 1) ? 0 : 1;
    
    // Update the starline_timings table
    $updateQuery = "UPDATE `starline_timings` SET `active`='$new_status' WHERE `sn`='$sn'";
    
    if (mysqli_query($con, $updateQuery)) {
        echo $new_status; // Send strictly "0" or "1" back to JavaScript
    } else {
        echo "error";
    }
    exit; 
}
ob_end_flush(); 
?>

