        <?php
        $count = 1;
        // Fetching from starline_timings as requested
        $query = "SELECT * FROM `starline_timings` ORDER BY close ASC"; 
        $result = mysqli_query($con, $query);

        if (mysqli_num_rows($result) > 0) {
            while ($row = mysqli_fetch_assoc($result)) {
                $status = $row['active'];
                $btnClass = ($status == 1) ? '' : 'off';
                $btnText = ($status == 1) ? 'ON' : 'OFF';
                $displayTime = date("h:i A", strtotime($row['close']));
        ?>
            
            <div class="game-card">
                <div class="gc-left">
                    <div class="gc-sno"><?php echo $count; ?></div>
                    <div class="gc-info">
                        <span class="gc-name"><?php echo $row['name']; ?></span>
                        <span class="gc-time">Closing Time: <?php echo $displayTime; ?></span>
                    </div>
                </div>
                <div class="gc-right">
                    <button class="toggle-btn <?php echo $btnClass; ?>" 
                            data-sn="<?php echo $row['sn']; ?>" 
                            data-status="<?php echo $status; ?>"
                            onclick="toggleStarline(this)">
                        <?php echo $btnText; ?>
                    </button>
                </div>
            </div>

        <?php
                $count++;
            }
        } else {
            echo "<div style='text-align:center; padding:20px; color:#999;'>No Starline Timings found.</div>";
